import React, { useEffect, useState } from 'react';
import { motion } from 'framer-motion';
import {
  FiSettings,
  FiUser,
  FiLock,
  FiBell,
  FiMoon,
  FiSun,
} from 'react-icons/fi';

import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';

const Settings = () => {
  const { user, updateUser } = useAuth();

  // =========================
  // STATES
  // =========================

  const [darkMode, setDarkMode] = useState(() => {
    const savedTheme = localStorage.getItem('darkMode');
    return savedTheme ? JSON.parse(savedTheme) : true;
  });

  const [notifications, setNotifications] = useState(() => {
    const savedNotifications = localStorage.getItem('notifications');

    return savedNotifications
      ? JSON.parse(savedNotifications)
      : {
          assignments: true,
          exams: true,
          grades: true,
          announcements: false,
        };
  });

  const [profile, setProfile] = useState({
    name: '',
    email: '',
  });

  const [passwords, setPasswords] = useState({
    currentPassword: '',
    newPassword: '',
    confirmPassword: '',
  });

  // =========================
  // EFFECTS
  // =========================

  useEffect(() => {
    document.documentElement.setAttribute(
      'data-theme',
      darkMode ? 'dark' : 'light'
    );

    localStorage.setItem(
      'darkMode',
      JSON.stringify(darkMode)
    );
  }, [darkMode]);

  useEffect(() => {
    localStorage.setItem(
      'notifications',
      JSON.stringify(notifications)
    );
  }, [notifications]);

  useEffect(() => {
    if (user) {
      setProfile({
        name: user.name || '',
        email: user.email || '',
      });
    }
  }, [user]);

  // =========================
  // UPDATE PROFILE
  // =========================

  const handleProfileSave = async () => {
    try {
      const userInfo = JSON.parse(
        localStorage.getItem('userInfo')
      );

      if (!userInfo || !userInfo.token) {
        toast.error('Please login again');
        return;
      }

      const res = await fetch(
        'http://localhost:5000/api/auth/profile',
        {
          method: 'PUT',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${userInfo.token}`,
          },
          body: JSON.stringify({
            name: profile.name,
            email: profile.email,
          }),
        }
      );

      const data = await res.json();

      if (!res.ok) {
        throw new Error(
          data.message || 'Failed to update profile'
        );
      }

      const updatedUser = {
        ...userInfo,
        ...data,
      };

      localStorage.setItem(
        'userInfo',
        JSON.stringify(updatedUser)
      );

      if (updateUser) {
        updateUser(updatedUser);
      }

      toast.success('Profile updated successfully!');
    } catch (error) {
      console.log(error);
      toast.error(
        error.message || 'Failed to update profile'
      );
    }
  };

  // =========================
  // CHANGE PASSWORD
  // =========================

  const handlePasswordSave = async () => {
    const {
      currentPassword,
      newPassword,
      confirmPassword,
    } = passwords;

    // Validation

    if (
      !currentPassword ||
      !newPassword ||
      !confirmPassword
    ) {
      toast.error('Please fill all password fields');
      return;
    }

    if (newPassword.length < 6) {
      toast.error(
        'Password must be at least 6 characters'
      );
      return;
    }

    if (newPassword !== confirmPassword) {
      toast.error('Passwords do not match');
      return;
    }

    try {
      const userInfo = JSON.parse(
        localStorage.getItem('userInfo')
      );

      if (!userInfo || !userInfo.token) {
        toast.error('Please login again');
        return;
      }

      const res = await fetch(
        'http://localhost:5000/api/auth/change-password',
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${userInfo.token}`,
          },
          body: JSON.stringify({
            currentPassword,
            newPassword,
          }),
        }
      );

      const data = await res.json();

      if (!res.ok) {
        throw new Error(
          data.message || 'Failed to change password'
        );
      }

      setPasswords({
        currentPassword: '',
        newPassword: '',
        confirmPassword: '',
      });

      toast.success('Password updated successfully!');
    } catch (error) {
      console.log(error);
      toast.error(
        error.message || 'Something went wrong'
      );
    }
  };

  // =========================
  // COMPONENTS
  // =========================

  const Section = ({ icon, title, children }) => (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      style={{
        background: 'var(--card-bg)',
        border: '1px solid var(--border)',
        borderRadius: '16px',
        padding: '24px',
        marginBottom: '20px',
      }}
    >
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '10px',
          marginBottom: '20px',
        }}
      >
        <span
          style={{
            color: '#667eea',
            fontSize: '1.1rem',
          }}
        >
          {icon}
        </span>

        <h3
          style={{
            margin: 0,
            fontSize: '1rem',
            fontWeight: '600',
          }}
        >
          {title}
        </h3>
      </div>

      {children}
    </motion.div>
  );

  const inputStyle = {
    width: '100%',
    padding: '10px 14px',
    background: 'rgba(255,255,255,0.05)',
    border: '1px solid var(--border)',
    borderRadius: '10px',
    color: 'var(--text-primary)',
    fontSize: '0.9rem',
    marginBottom: '12px',
    boxSizing: 'border-box',
    outline: 'none',
  };

  const buttonStyle = {
    padding: '10px 24px',
    background: 'var(--gradient-primary)',
    border: 'none',
    borderRadius: '10px',
    color: '#fff',
    fontWeight: '600',
    cursor: 'pointer',
    fontSize: '0.9rem',
  };

  const Toggle = ({ checked, onChange }) => (
    <div
      onClick={() => onChange(!checked)}
      style={{
        width: '44px',
        height: '24px',
        borderRadius: '12px',
        background: checked
          ? '#667eea'
          : 'rgba(255,255,255,0.1)',
        cursor: 'pointer',
        position: 'relative',
        transition: 'background 0.3s',
        flexShrink: 0,
      }}
    >
      <div
        style={{
          position: 'absolute',
          top: '3px',
          left: checked ? '23px' : '3px',
          width: '18px',
          height: '18px',
          borderRadius: '50%',
          background: '#fff',
          transition: 'left 0.3s',
        }}
      />
    </div>
  );

  // =========================
  // UI
  // =========================

  return (
    <div
      style={{
        padding: '30px',
        maxWidth: '650px',
        margin: '0 auto',
      }}
    >
      {/* HEADER */}

      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: '12px',
          marginBottom: '8px',
        }}
      >
        <FiSettings size={24} color="#667eea" />

        <h1
          style={{
            fontSize: '1.8rem',
            fontWeight: '700',
            margin: 0,
          }}
        >
          Settings
        </h1>
      </div>

      <p
        style={{
          color: 'var(--text-muted)',
          marginBottom: '30px',
        }}
      >
        Manage your account preferences
      </p>

      {/* PROFILE */}

      <Section
        icon={<FiUser />}
        title="Profile Information"
      >
        <input
          style={inputStyle}
          type="text"
          placeholder="Full Name"
          value={profile.name}
          onChange={(e) =>
            setProfile({
              ...profile,
              name: e.target.value,
            })
          }
        />

        <input
          style={inputStyle}
          type="email"
          placeholder="Email Address"
          value={profile.email}
          onChange={(e) =>
            setProfile({
              ...profile,
              email: e.target.value,
            })
          }
        />

        <button
          type="button"
          onClick={handleProfileSave}
          style={buttonStyle}
        >
          Save Changes
        </button>
      </Section>

      {/* PASSWORD */}

      <Section
        icon={<FiLock />}
        title="Change Password"
      >
        <form
          onSubmit={(e) => {
            e.preventDefault();
          }}
        >
          <input
            style={inputStyle}
            type="password"
            placeholder="Current Password"
            value={passwords.currentPassword}
            onChange={(e) =>
              setPasswords({
                ...passwords,
                currentPassword: e.target.value,
              })
            }
          />

          <input
            style={inputStyle}
            type="password"
            placeholder="New Password"
            value={passwords.newPassword}
            onChange={(e) =>
              setPasswords({
                ...passwords,
                newPassword: e.target.value,
              })
            }
          />

          <input
            style={inputStyle}
            type="password"
            placeholder="Confirm New Password"
            value={passwords.confirmPassword}
            onChange={(e) =>
              setPasswords({
                ...passwords,
                confirmPassword: e.target.value,
              })
            }
          />

          <button
            type="button"
            onClick={handlePasswordSave}
            style={buttonStyle}
          >
            Update Password
          </button>
        </form>
      </Section>

      {/* NOTIFICATIONS */}

      <Section
        icon={<FiBell />}
        title="Notification Preferences"
      >
        {Object.entries(notifications).map(
          ([key, value]) => (
            <div
              key={key}
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                marginBottom: '14px',
              }}
            >
              <span
                style={{
                  textTransform: 'capitalize',
                  fontSize: '0.9rem',
                }}
              >
                {key} notifications
              </span>

              <Toggle
                checked={value}
                onChange={(v) =>
                  setNotifications({
                    ...notifications,
                    [key]: v,
                  })
                }
              />
            </div>
          )
        )}
      </Section>

      {/* APPEARANCE */}

      <Section
        icon={darkMode ? <FiMoon /> : <FiSun />}
        title="Appearance"
      >
        <div
          style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
          }}
        >
          <span style={{ fontSize: '0.9rem' }}>
            Dark Mode
          </span>

          <Toggle
            checked={darkMode}
            onChange={setDarkMode}
          />
        </div>
      </Section>
    </div>
  );
};

export default Settings;
